import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { CorporationsListParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CorporationsListParser';

export class CorporationsListEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, CorporationsListParser);
    }

    public getParser(): CorporationsListParser {
        return this.parser as CorporationsListParser;
    }
}
